.game-container {
    width: 80%;
    margin: 40px auto;
    background-color: #f0f0f0;
    padding: 20px;
    border: 1px solid #ccc;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

.controls {
    display: flex;
    justify-content: space-between;
}

#play-btn, #pause-btn, #stop-btn, #save-btn {
    margin: 10px 20px;
    padding: 10px 20px;
    border: none;
    border-radius: 5px;
    background-color: #4CAF50;
    color: #fff;
    cursor: pointer;
}

#play-btn:hover, #pause-btn:hover, #stop-btn:hover, #save-btn:hover {
    background-color: #3e8e41;
}

#format-select {
    margin: 10px 20px;
    padding: 10px 20px;
    border: none;
    border-radius: 5px;
    background-color: #f0f0f0;
    width: 200px;
}

#bpm-input {
    width: 50px;
    height: 30px;
    padding: 10px;
    border: none;
    border-radius: 5px;
}

#bpm-btn {
    margin: 10px 20px;
    padding: 10px 20px;
    border: none;
    border-radius: 5px;
    background-color: #4CAF50;
    color: #fff;
    cursor: pointer;
}

#bpm-btn:hover {
    background-color: #3e8e41;
}

.loop-container {
    display: flex;
    align-items: center;
}

#loop-select {
    margin: 10px 20px;
    padding: 10px;
    border: none;
    border-radius: 5px;
    background-color: #f0f0f0;
    width: 200px;
}

#range-loop {
    margin: 10px;
    width: 100px;
}

.track-container {
    display: flex;
    align-items: center;
}

.track {
    margin: 10px;
    padding: 20px;
    border: 1px solid #ccc;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

.track h1 {
    margin: 10px 0;
}

label {
    margin: 10px 0;
}

input[type="radio"] {
    margin: 10px 10px;
}

input[type="range"] {
    margin: 10px 0;
    width: 100px;
}

#canvas {
    border: 1px solid #ccc;
}
